import { Icon as IconifyIcon } from '@iconify/react'
import React from 'react'

interface IconProps {
  icon?: string
  size?: string | number
  width?: string | number
  height?: string | number
  color?: string
  style?: React.CSSProperties
  children?: string
}

export function Icon({ icon, size, width, height, color, style, children }: IconProps) {
  const iconName = icon || children
  if (!iconName) {
    return null
  }

  const fontSize = size ? (typeof size === 'number' ? `${size}px` : size) : '1.125em'
  const verticalAlign = style?.verticalAlign ? style?.verticalAlign : '-0.15em'

  const svgStyle: React.CSSProperties = {
    verticalAlign,
    display: 'inline-flex',
    alignItems: 'center',
    width: '1em',
    height: '1em',
    ...(width != null ? { width: typeof width === 'number' ? `${width}px` : width } : {}),
    ...(height != null ? { height: typeof height === 'number' ? `${height}px` : height } : {}),
    ...(style ?? {}),
  }

  return (
    <span style={{ fontSize }}>
      <IconifyIcon
        icon={iconName}
        color={color}
        style={svgStyle}
      >
      </IconifyIcon>
    </span>
  )
}

export function CHECK() {
  return (
    <span>
      <IconifyIcon icon="mdi:check" height="24" style={{ verticalAlign: '-0.35em', color: '#22c55e', display: 'inline-flex', alignItems: 'center' }}></IconifyIcon>
    </span>
  )
}

export function CLOSE() {
  return (
    <span>
      <IconifyIcon icon="mdi:close" height="24" style={{ verticalAlign: '-0.35em', color: '#ef4444', display: 'inline-flex', alignItems: 'center' }}></IconifyIcon>
    </span>
  )
}

